import{_ as e,c as s,o as i,a1 as o}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Conceitos Principais: Ecossistema de Skills Unificado | OpenSkills","description":"Aprenda os conceitos principais e o funcionamento do OpenSkills. Como um carregador de skills unificado, suporta compartilhamento de skills entre múltiplos agentes, com carregamento progressivo.","frontmatter":{"title":"Conceitos Principais: Ecossistema de Skills Unificado | OpenSkills","sidebarTitle":"Compartilhar Skills entre Ferramentas de IA","subtitle":"Conceitos Principais: Ecossistema de Skills Unificado | OpenSkills","description":"Aprenda os conceitos principais e o funcionamento do OpenSkills. Como um carregador de skills unificado, suporta compartilhamento de skills entre múltiplos agentes, com carregamento progressivo.","tags":["Introdução de Conceitos","Conceitos Principais"],"prerequisite":[],"order":2},"headers":[],"relativePath":"pt/numman-ali/openskills/start/what-is-openskills/index.md","filePath":"pt/numman-ali/openskills/start/what-is-openskills/index.md"}'),t={name:"pt/numman-ali/openskills/start/what-is-openskills/index.md"};function l(r,a,n,d,c,p){return i(),s("div",null,[...a[0]||(a[0]=[o(`<h1 id="o-que-e-o-openskills" tabindex="-1">O que é o OpenSkills? <a class="header-anchor" href="#o-que-e-o-openskills" aria-label="Permalink to &quot;O que é o OpenSkills?&quot;">​</a></h1><h2 id="o-que-voce-podera-fazer-apos-concluir" tabindex="-1">O que você poderá fazer após concluir <a class="header-anchor" href="#o-que-voce-podera-fazer-apos-concluir" aria-label="Permalink to &quot;O que você poderá fazer após concluir&quot;">​</a></h2><ul><li>Compreender o valor principal e o funcionamento do OpenSkills</li><li>Saber a relação entre OpenSkills e Claude Code</li><li>Avaliar quando usar o OpenSkills em vez do sistema de skills integrado</li><li>Entender como fazer múltiplos agentes de codificação de IA compartilharem um ecossistema de skills</li></ul><div class="info custom-block"><p class="custom-block-title">Pré-requisitos</p><p>Este tutorial assume que você conhece ferramentas básicas de codificação com IA (como Claude Code, Cursor, etc.), mas não requer nenhuma experiência prévia com OpenSkills.</p></div><hr><h2 id="o-dilema-que-voce-enfrenta-agora" tabindex="-1">O dilema que você enfrenta agora <a class="header-anchor" href="#o-dilema-que-voce-enfrenta-agora" aria-label="Permalink to &quot;O dilema que você enfrenta agora&quot;">​</a></h2><p>Você pode encontrar estes cenários:</p><ul><li><strong>Skills que funcionam bem no Claude Code desaparecem quando você muda de ferramenta de IA</strong>: por exemplo, skills de processamento de PDF do Claude Code não funcionam no Cursor</li><li><strong>Instalação repetida de skills em ferramentas diferentes</strong>: cada ferramenta de IA precisa de configuração de skills separada, com alto custo de gerenciamento</li><li><strong>Quer usar skills privadas, mas o Marketplace oficial não suporta</strong>: skills desenvolvidas internamente ou por você não podem ser compartilhadas facilmente com a equipe</li></ul><p>Esses problemas são essencialmente: <strong>formatos de skills não unificados, impossibilitando o compartilhamento entre ferramentas</strong>.</p><hr><h2 id="ideia-central-formato-de-skills-unificado" tabindex="-1">Ideia central: formato de skills unificado <a class="header-anchor" href="#ideia-central-formato-de-skills-unificado" aria-label="Permalink to &quot;Ideia central: formato de skills unificado&quot;">​</a></h2><p>A ideia central do OpenSkills é simples: <strong>transformar o sistema de skills do Claude Code em um carregador de skills universal</strong>.</p><h3 id="o-que-e" tabindex="-1">O que é <a class="header-anchor" href="#o-que-e" aria-label="Permalink to &quot;O que é&quot;">​</a></h3><p><strong>OpenSkills</strong> é um carregador universal do sistema de skills da Anthropic, permitindo que qualquer agente de codificação de IA (Claude Code, Cursor, Windsurf, Aider, etc.) use skills no formato padrão SKILL.md.</p><p>Em resumo: <strong>um instalador, servindo todas as ferramentas de codificação com IA</strong>.</p><h3 id="que-problemas-ele-resolve" tabindex="-1">Que problemas ele resolve <a class="header-anchor" href="#que-problemas-ele-resolve" aria-label="Permalink to &quot;Que problemas ele resolve&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Problema</th><th>Solução</th></tr></thead><tbody><tr><td>Formatos de skills não unificados</td><td>Usar o formato padrão SKILL.md do Claude Code</td></tr><tr><td>Skills não podem ser compartilhadas entre ferramentas</td><td>Gerar AGENTS.md unificado, legível por todas as ferramentas</td></tr><tr><td>Gerenciamento de skills disperso</td><td>Comandos unificados para instalar, atualizar e remover</td></tr><tr><td>Dificuldade em compartilhar skills privadas</td><td>Suporte para instalar de caminhos locais e repositórios git privados</td></tr></tbody></table><hr><h2 id="valor-principal" tabindex="-1">Valor principal <a class="header-anchor" href="#valor-principal" aria-label="Permalink to &quot;Valor principal&quot;">​</a></h2><p>O OpenSkills oferece os seguintes valores principais:</p><h3 id="_1-padrao-unificado" tabindex="-1">1. Padrão unificado <a class="header-anchor" href="#_1-padrao-unificado" aria-label="Permalink to &quot;1. Padrão unificado&quot;">​</a></h3><p>Todos os agentes usam o mesmo formato de skills e descrição AGENTS.md, sem necessidade de aprender novos formatos.</p><ul><li><strong>Totalmente compatível com Claude Code</strong>: mesmo formato de prompts, mesmo Marketplace, mesma estrutura de pastas</li><li><strong>SKILL.md padronizado</strong>: definição de skills clara, fácil de desenvolver e manter</li></ul><h3 id="_2-carregamento-progressivo" tabindex="-1">2. Carregamento progressivo <a class="header-anchor" href="#_2-carregamento-progressivo" aria-label="Permalink to &quot;2. Carregamento progressivo&quot;">​</a></h3><p>Carrega skills sob demanda, mantendo o contexto da IA enxuto.</p><ul><li>Não precisa carregar todas as skills de uma vez</li><li>O agente de IA carrega dinamicamente as skills relevantes conforme a tarefa</li><li>Evita explosão de contexto, melhorando a qualidade das respostas</li></ul><h3 id="_3-suporte-a-multiplos-agentes" tabindex="-1">3. Suporte a múltiplos agentes <a class="header-anchor" href="#_3-suporte-a-multiplos-agentes" aria-label="Permalink to &quot;3. Suporte a múltiplos agentes&quot;">​</a></h3><p>Um conjunto de skills serve vários agentes, sem necessidade de instalação repetida.</p><ul><li>Claude Code, Cursor, Windsurf, Aider compartilham o mesmo conjunto de skills</li><li>Interface unificada de gerenciamento de skills</li><li>Reduz custos de configuração e manutenção</li></ul><h3 id="_4-amigavel-ao-codigo-aberto" tabindex="-1">4. Amigável ao código aberto <a class="header-anchor" href="#_4-amigavel-ao-codigo-aberto" aria-label="Permalink to &quot;4. Amigável ao código aberto&quot;">​</a></h3><p>Suporta caminhos locais e repositórios git privados, adequado para colaboração em equipe.</p><ul><li>Instalar skills do sistema de arquivos local (em desenvolvimento)</li><li>Instalar de repositórios git privados (compartilhamento interno da empresa)</li><li>Skills podem ser versionados junto com o projeto</li></ul><h3 id="_5-execucao-local" tabindex="-1">5. Execução local <a class="header-anchor" href="#_5-execucao-local" aria-label="Permalink to &quot;5. Execução local&quot;">​</a></h3><p>Sem upload de dados, privacidade e segurança garantidas.</p><ul><li>Todos os arquivos de skills são armazenados localmente</li><li>Não depende de serviços em nuvem, sem risco de vazamento de dados</li><li>Adequado para projetos sensíveis e ambientes corporativos</li></ul><hr><h2 id="como-funciona" tabindex="-1">Como funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Como funciona&quot;">​</a></h2><p>O fluxo de trabalho do OpenSkills é simples, dividido em três etapas:</p><h3 id="etapa-1-instalar-skills" tabindex="-1">Etapa 1: Instalar skills <a class="header-anchor" href="#etapa-1-instalar-skills" aria-label="Permalink to &quot;Etapa 1: Instalar skills&quot;">​</a></h3><p>Instale skills do GitHub, caminho local ou repositório git privado no seu projeto.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Instalar do repositório oficial da Anthropic</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> anthropics/skills</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Instalar de caminho local</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./my-skills</span></span></code></pre></div><p>As skills serão instaladas no diretório <code>.claude/skills/</code> do projeto (padrão), ou no diretório <code>.agent/skills/</code> (ao usar <code>--universal</code>).</p><h3 id="etapa-2-sincronizar-para-agents-md" tabindex="-1">Etapa 2: Sincronizar para AGENTS.md <a class="header-anchor" href="#etapa-2-sincronizar-para-agents-md" aria-label="Permalink to &quot;Etapa 2: Sincronizar para AGENTS.md&quot;">​</a></h3><p>Sincronize as skills instaladas para o arquivo AGENTS.md, gerando uma lista de skills legível pelo agente de IA.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sync</span></span></code></pre></div><p>O AGENTS.md conterá XML similar a este:</p><div class="language-xml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">available_skills</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">skill</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;pdf&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;Comprehensive PDF manipulation toolkit for extracting text and tables...&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">location</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;project&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">location</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">skill</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">available_skills</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><h3 id="etapa-3-agente-de-ia-carrega-as-skills" tabindex="-1">Etapa 3: Agente de IA carrega as skills <a class="header-anchor" href="#etapa-3-agente-de-ia-carrega-as-skills" aria-label="Permalink to &quot;Etapa 3: Agente de IA carrega as skills&quot;">​</a></h3><p>Quando o agente de IA precisa usar uma skill, carrega o conteúdo da skill através do seguinte comando:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> read</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">skill-nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>O agente de IA carrega dinamicamente o conteúdo da skill no contexto e executa a tarefa.</p><hr><h2 id="relacao-com-claude-code" tabindex="-1">Relação com Claude Code <a class="header-anchor" href="#relacao-com-claude-code" aria-label="Permalink to &quot;Relação com Claude Code&quot;">​</a></h2><p>OpenSkills e Claude Code têm uma relação complementar, não de substituição.</p><h3 id="formato-totalmente-compativel" tabindex="-1">Formato totalmente compatível <a class="header-anchor" href="#formato-totalmente-compativel" aria-label="Permalink to &quot;Formato totalmente compatível&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Aspecto</th><th>Claude Code</th><th>OpenSkills</th></tr></thead><tbody><tr><td><strong>Formato de prompts</strong></td><td>XML <code>&lt;available_skills&gt;</code></td><td>Mesmo XML</td></tr><tr><td><strong>Armazenamento de skills</strong></td><td><code>.claude/skills/</code></td><td><code>.claude/skills/</code> (padrão)</td></tr><tr><td><strong>Chamada de skills</strong></td><td>Ferramenta <code>Skill(&quot;name&quot;)</code></td><td><code>npx openskills read &lt;name&gt;</code></td></tr><tr><td><strong>Marketplace</strong></td><td>Marketplace da Anthropic</td><td>GitHub (anthropics/skills)</td></tr><tr><td><strong>Carregamento progressivo</strong></td><td>✅</td><td>✅</td></tr></tbody></table><h3 id="comparacao-de-cenarios-de-uso" tabindex="-1">Comparação de cenários de uso <a class="header-anchor" href="#comparacao-de-cenarios-de-uso" aria-label="Permalink to &quot;Comparação de cenários de uso&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Cenário</th><th>Ferramenta recomendada</th><th>Motivo</th></tr></thead><tbody><tr><td>Usar apenas Claude Code</td><td>Sistema integrado do Claude Code</td><td>Sem necessidade de instalação adicional, suporte oficial</td></tr><tr><td>Usar múltiplas ferramentas de IA</td><td>OpenSkills</td><td>Gerenciamento unificado, evita repetição</td></tr><tr><td>Precisa de skills privadas</td><td>OpenSkills</td><td>Suporta repositórios locais e privados</td></tr><tr><td>Colaboração em equipe</td><td>OpenSkills</td><td>Skills podem ser versionadas, fáceis de compartilhar</td></tr></tbody></table><hr><h2 id="explicacao-dos-locais-de-instalacao" tabindex="-1">Explicação dos locais de instalação <a class="header-anchor" href="#explicacao-dos-locais-de-instalacao" aria-label="Permalink to &quot;Explicação dos locais de instalação&quot;">​</a></h2><p>O OpenSkills suporta três locais de instalação:</p><table tabindex="0"><thead><tr><th>Local de instalação</th><th>Comando</th><th>Cenário aplicável</th></tr></thead><tbody><tr><td><strong>Local do projeto</strong></td><td>Padrão</td><td>Uso em projeto individual, skills versionadas com o projeto</td></tr><tr><td><strong>Instalação global</strong></td><td><code>--global</code></td><td>Compartilhar skills comuns entre todos os projetos</td></tr><tr><td><strong>Modo Universal</strong></td><td><code>--universal</code></td><td>Ambiente multi-agente, evita conflito com Claude Code</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Quando usar o modo Universal?</p><p>Se você usa Claude Code e outros agentes de codificação (como Cursor, Windsurf) simultaneamente, use <code>--universal</code> para instalar em <code>.agent/skills/</code>, permitindo que múltiplos agentes compartilhem o mesmo conjunto de skills, evitando conflitos.</p></div><hr><h2 id="ecossistema-de-skills" tabindex="-1">Ecossistema de skills <a class="header-anchor" href="#ecossistema-de-skills" aria-label="Permalink to &quot;Ecossistema de skills&quot;">​</a></h2><p>O OpenSkills usa o mesmo ecossistema de skills do Claude Code:</p><h3 id="biblioteca-de-skills-oficial" tabindex="-1">Biblioteca de skills oficial <a class="header-anchor" href="#biblioteca-de-skills-oficial" aria-label="Permalink to &quot;Biblioteca de skills oficial&quot;">​</a></h3><p>Repositório de skills mantido oficialmente pela Anthropic: <a href="https://github.com/anthropics/skills" target="_blank" rel="noreferrer">anthropics/skills</a></p><p>Inclui skills comuns:</p><ul><li>Processamento de PDF</li><li>Geração de imagens</li><li>Análise de dados</li><li>E mais...</li></ul><h3 id="skills-da-comunidade" tabindex="-1">Skills da comunidade <a class="header-anchor" href="#skills-da-comunidade" aria-label="Permalink to &quot;Skills da comunidade&quot;">​</a></h3><p>Qualquer repositório GitHub pode ser uma fonte de skills, desde que contenha um arquivo SKILL.md.</p><h3 id="skills-personalizadas" tabindex="-1">Skills personalizadas <a class="header-anchor" href="#skills-personalizadas" aria-label="Permalink to &quot;Skills personalizadas&quot;">​</a></h3><p>Você pode criar suas próprias skills, usando o formato padrão, e compartilhar com a equipe.</p><hr><h2 id="resumo-desta-licao" tabindex="-1">Resumo desta lição <a class="header-anchor" href="#resumo-desta-licao" aria-label="Permalink to &quot;Resumo desta lição&quot;">​</a></h2><p>A ideia central do OpenSkills é:</p><ol><li><strong>Padrão unificado</strong>: usar o formato SKILL.md do Claude Code</li><li><strong>Suporte a múltiplos agentes</strong>: permitir que todas as ferramentas de codificação com IA compartilhem o ecossistema de skills</li><li><strong>Carregamento progressivo</strong>: carregar sob demanda, mantendo o contexto enxuto</li><li><strong>Execução local</strong>: sem upload de dados, privacidade e segurança garantidas</li><li><strong>Amigável ao código aberto</strong>: suporta repositórios locais e privados</li></ol><p>Com o OpenSkills, você pode:</p><ul><li>Alternar entre diferentes ferramentas de IA sem problemas</li><li>Gerenciar todas as skills de forma unificada</li><li>Usar e compartilhar skills privadas</li><li>Aumentar a eficiência do desenvolvimento</li></ul><hr><h2 id="proxima-licao" tabindex="-1">Próxima lição <a class="header-anchor" href="#proxima-licao" aria-label="Permalink to &quot;Próxima lição&quot;">​</a></h2><blockquote><p>Na próxima lição aprenderemos <strong><a href="./../../instalacao/">Instalar a ferramenta OpenSkills</a></strong></p><p>Você aprenderá:</p><ul><li>Como verificar o ambiente Node.js e Git</li><li>Usar npx ou instalar o OpenSkills globalmente</li><li>Verificar se a instalação foi bem-sucedida</li><li>Resolver problemas comuns de instalação</li></ul></blockquote><hr><h2 id="apendice-referencia-do-codigo-fonte" tabindex="-1">Apêndice: Referência do código-fonte <a class="header-anchor" href="#apendice-referencia-do-codigo-fonte" aria-label="Permalink to &quot;Apêndice: Referência do código-fonte&quot;">​</a></h2><details><summary><strong>Clique para expandir e ver a localização do código-fonte</strong></summary><blockquote><p>Última atualização: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidade</th><th>Caminho do arquivo</th><th>Linhas</th></tr></thead><tbody><tr><td>Definições de tipos principais</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/types.ts#L1-L24" target="_blank" rel="noreferrer"><code>src/types.ts</code></a></td><td>1-24</td></tr><tr><td>Interface Skill</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/types.ts#L1-L6" target="_blank" rel="noreferrer"><code>src/types.ts</code></a></td><td>1-6</td></tr><tr><td>Interface SkillLocation</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/types.ts#L8-L12" target="_blank" rel="noreferrer"><code>src/types.ts</code></a></td><td>8-12</td></tr><tr><td>Interface InstallOptions</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/types.ts#L14-L18" target="_blank" rel="noreferrer"><code>src/types.ts</code></a></td><td>14-18</td></tr><tr><td>Interface SkillMetadata</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/types.ts#L20-L24" target="_blank" rel="noreferrer"><code>src/types.ts</code></a></td><td>20-24</td></tr></tbody></table><p><strong>Interfaces principais</strong>:</p><ul><li><code>Skill</code>: informações da skill instalada (name, description, location, path)</li><li><code>SkillLocation</code>: informações de localização da skill (path, baseDir, source)</li><li><code>InstallOptions</code>: opções do comando de instalação (global, universal, yes)</li><li><code>SkillMetadata</code>: metadados da skill (name, description, context)</li></ul><p><strong>Fonte dos conceitos principais</strong>:</p><ul><li>README.md:22-86 - Capítulo &quot;What Is OpenSkills?&quot;</li></ul></details>`,86)])])}const u=e(t,[["render",l]]);export{h as __pageData,u as default};
